import React from 'react'
import { Arrow } from '@fs/zion-icon'
import { IconButton } from '@fs/zion-ui'
import { useHistory, useParams } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

// Override the color when in header for improved contrast
function HeaderBackIcon() {
  return <Arrow direction="backward" color="#ffffff" />
}

function getReturnLocation({ cid, pid, pathname }) {
  if (pid || pathname.includes('details')) {
    return buildChatRoute(CHAT_ROUTE_KEY.CHAT, { cid })
  }
  return buildChatRoute(CHAT_ROUTE_KEY.CHATS)
}

export default function BackButton({ inHeader = false, ...props }) {
  const { cid, pid } = useParams()
  const history = useHistory()
  const { t } = useTranslation()
  const onBackMenuIconClick = () => {
    const returnLocation = getReturnLocation({ cid, pid, pathname: history?.location?.pathname })
    history.push({
      pathname: returnLocation,
      state: {
        from: history.location,
      },
    })
  }

  return (
    <IconButton
      title={t('common-ui:back.action', 'Back')}
      data-testid="back-button"
      Icon={inHeader ? HeaderBackIcon : Arrow}
      iconDirection="backward"
      onClick={onBackMenuIconClick}
      {...props}
    />
  )
}
