import React, { Fragment } from 'react'
import { useTranslation } from 'react-i18next'
import { useHistory } from '@fs/zion-router'
import { Divider, Paragraph, Separator } from '@fs/zion-ui'
import { css } from '@linaria/core'
import ChatChannelListItem from './ChatChannelListItem'
import { isChannelBlocked, sortChannelsAndThreadsByLastUpdated } from '../../helpers/stream/streamChatHelper'
import { useChatState } from '../../providers/ChatStateProvider'
import { useChatMultiSelectState } from '../../providers/ChatMultiSelectProvider'
import useChatFlags from '../../hooks/useChatFlags'

const listItemStyles = css`
  list-style: none;
`

export default function ChatChannelListItems({
  list,
  hideMenuIcon,
  lastElementRef,
  sortByLastMessage = true,
  isEventList,
  ...props
}) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const { multiSelectIsActive } = useChatMultiSelectState()
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()

  const filteredList = list?.filter((channel) => {
    const baseChannel = channel?.isStreamThread
      ? channel.baseChannel || channel.state?.getLatestValue?.()?.channel || channel
      : channel
    return !isChannelBlocked({ channel: baseChannel, client })
  })

  const sortedList = sortByLastMessage ? sortChannelsAndThreadsByLastUpdated(filteredList) : filteredList
  const history = useHistory()

  return (
    <>
      {sortedList && sortedList.length > 0 ? (
        sortedList.map((item, index) => {
          // When the user clicks on the back arrow, it pushes the path of the previous chat to history.location.state.from, which includes the chat CID at the end of the path.
          // This line is just extracting that CID from the previous chat's path.
          const previousChatCid = history.location.state?.from?.pathname?.split('/').slice(-1)[0]
          const key = `${item.id} - ${index}`
          return (
            <Fragment key={key}>
              <ChatChannelListItem
                item={item}
                hideMenuIcon={hideMenuIcon}
                lastElementRef={index === sortedList.length - 1 ? lastElementRef : undefined}
                previousChatCid={previousChatCid}
                multiSelectIsActive={multiSelectIsActive}
                {...props}
              />
              {messagingChatLeftPanelRedesignIsOn && !isEventList && <Divider />}
            </Fragment>
          )
        })
      ) : (
        <li className={listItemStyles} key="empty-list">
          <Paragraph centered size="sm">
            {t('chat.empty-section.heading', 'This section is empty.')}
          </Paragraph>
          <Separator size="xs" />
        </li>
      )}
    </>
  )
}
