import React, { useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import { Button, List, ListSubSection, MarginBox, Row } from '@fs/zion-ui'
import { Arrow, NoticeLoading } from '@fs/zion-icon'
import BackButton from '../chat-buttons/BackButton'
import ChatChannelListItems from '../chat-window/chat-window-chats/ChatChannelListItems'
import useChatLog from '../hooks/useChatLog'
import { useChatState } from '../providers/ChatStateProvider'
import { useOpenExistingChannel } from '../hooks/channelHooks'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { QUERY_CHANNELS_PAGE_SIZE, queryPageOfChannelsByType } from '../helpers/stream/streamChatChannelsHelper'
import { CHANNEL_CATEGORY_MAP } from '../services/fsChat/fsChannelEnums'

export default function ChatHiddenContent({ isNarrow }) {
  const { client } = useChatState()
  const openExistingChannel = useOpenExistingChannel()
  const [t] = useTranslation()
  const [hiddenChannels, setHiddenChannels] = useState([])
  const [loading, setLoading] = useState(true)
  const [loadingMore, setLoadingMore] = useState(false)
  const { log, track } = useChatLog({ component: '[ChatHiddenContent]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const [showMore, setShowMore] = useState(false)

  useEffect(() => {
    let isUnmounted = false

    const fetchHiddenChannels = async () => {
      try {
        const results = await queryPageOfChannelsByType({
          client,
          types: Object.values(CHANNEL_CATEGORY_MAP).flatMap((cat) => cat.types),
          hidden: true,
          log,
        })

        if (!isUnmounted) {
          setHiddenChannels(results)
          setLoading(false)
          setShowMore(results?.length === QUERY_CHANNELS_PAGE_SIZE)
        }
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: 'Problem querying hidden channels' })
        }
      }
    }

    fetchHiddenChannels()

    return () => {
      isUnmounted = true
    }
  }, [client, handleBasicError, log])

  const handleShowMoreClick = async () => {
    try {
      setLoadingMore(true)
      const offset = hiddenChannels.length
      const newChannels = await queryPageOfChannelsByType({
        client,
        types: Object.values(CHANNEL_CATEGORY_MAP).flatMap((cat) => cat.types),
        hidden: true,
        offset,
        log,
      })
      setHiddenChannels([...hiddenChannels, ...newChannels])
      setShowMore(newChannels.length === QUERY_CHANNELS_PAGE_SIZE)
    } catch (err) {
      handleBasicError(err, { moreInfo: 'Problem paginating through hidden channels' })
    }
    setLoadingMore(false)
  }
  return (
    <ShadowScroller>
      <MarginBox marginX="sm" marginY="sm" style={{ maxWidth: '500px', flex: 1 }}>
        <Row>
          {!isNarrow && <BackButton data-testid="close-hidden-chats" />}
          <List growX>
            <ListSubSection heading={t('chat.hidden-chats.heading', 'Hidden Chats')}>
              {loading ? (
                <Row alignX="center">
                  <NoticeLoading />
                </Row>
              ) : (
                <>
                  <ChatChannelListItems
                    list={hiddenChannels}
                    onItemSelect={async (channel) => {
                      track({ link_name: `Unhide Channel` }, { chatChannelId: channel?.cid })
                      await channel.show()
                      openExistingChannel(channel)
                    }}
                    hideMenuIcon
                    sortByLastMessage={false}
                  />
                  {showMore && (
                    <Row alignX="center">
                      <Button
                        Icon={loadingMore ? NoticeLoading : Arrow}
                        iconDirection="down"
                        onClick={handleShowMoreClick}
                        data-testid="show-more-hidden-channels"
                      >
                        {t('chat.show-more.label', 'View More')}
                      </Button>
                    </Row>
                  )}
                </>
              )}
            </ListSubSection>
          </List>
        </Row>
      </MarginBox>
    </ShadowScroller>
  )
}
